import React, { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import api from "../api";
import ItemCard from "../components/ItemCard";

function Dashboard() {
  const navigate = useNavigate();
  const userId = localStorage.getItem("userId");
  const role = localStorage.getItem("role") || "USER";
  const [items, setItems] = useState([]);
  const [myItems, setMyItems] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [keyword, setKeyword] = useState("");
  const [category, setCategory] = useState("");
  const [location, setLocation] = useState("");
  const [status, setStatus] = useState("");
  const [viewMode, setViewMode] = useState("cards");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [dashboard, setDashboard] = useState({ lostCount: 0, foundCount: 0, latestItems: [] });

  const loadItems = async () => {
    setLoading(true);
    setError("");
    try {
      const response = await api.get("/items");
      setItems(response.data);
    } catch (err) {
      setError("Failed to load items. Please check backend.");
    } finally {
      setLoading(false);
    }
  };

  const loadDashboard = async () => {
    setError("");
    try {
      const response = await api.get("/items/dashboard");
      setDashboard(response.data);
    } catch (err) {
      setError("Failed to load dashboard stats.");
    }
  };

  const loadMyItems = async () => {
    if (!userId) {
      setMyItems([]);
      return;
    }
    try {
      const response = await api.get(`/items/user/${userId}`);
      setMyItems(response.data);
    } catch (err) {
      setError("Failed to load your reported items.");
    }
  };

  const loadNotifications = async () => {
    if (!userId) {
      setNotifications([]);
      return;
    }
    try {
      const response = await api.get(`/notifications/user/${userId}`);
      setNotifications(response.data);
    } catch (err) {
      setError("Failed to load notifications.");
    }
  };

  useEffect(() => {
    loadItems();
    loadDashboard();
    loadMyItems();
    loadNotifications();
  }, []);

  const handleSearch = async (e) => {
    if (e) {
      e.preventDefault();
    }
    setLoading(true);
    setError("");
    try {
      const response = await api.get(`/items/search?keyword=${encodeURIComponent(keyword)}`);
      setItems(response.data);
    } catch (err) {
      setError("Search request failed.");
    } finally {
      setLoading(false);
    }
  };

  const handleFilter = async () => {
    setLoading(true);
    setError("");
    try {
      const response = await api.get(
        `/items/filter?category=${encodeURIComponent(category)}&location=${encodeURIComponent(location)}&status=${encodeURIComponent(status)}`
      );
      setItems(response.data);
    } catch (err) {
      setError("Filter request failed.");
    } finally {
      setLoading(false);
    }
  };

  const totalItems = items.length;
  const claimedCount = items.filter((item) => item.status === "CLAIMED" || item.status === "RETURNED").length;
  const unreadCount = notifications.filter((notification) => !notification.read).length;
  const myLostCount = myItems.filter((item) => item.status === "LOST").length;

  const sortedMyItems = useMemo(() => myItems.slice().reverse(), [myItems]);

  const resetAll = () => {
    setKeyword("");
    setCategory("");
    setLocation("");
    setStatus("");
    loadItems();
  };

  const handleEdit = (item) => {
    navigate("/add-item", { state: { editItem: item } });
  };

  const handleReportFound = (item) => {
    navigate("/add-item", {
      state: {
        presetStatus: "FOUND",
        initialValues: {
          title: item.title,
          category: item.category,
          location: item.location,
          description: `Possible match for lost item: ${item.title}`
        }
      }
    });
  };

  const handleDelete = async (itemId) => {
    try {
      await api.delete(`/items/${itemId}?requesterId=${userId}&role=${role}`);
      loadItems();
      loadDashboard();
      loadMyItems();
    } catch (err) {
      setError(err.response?.data?.message || "Delete failed.");
    }
  };

  const handleMarkRead = async (notificationId) => {
    await api.put(`/notifications/${notificationId}/read`);
    loadNotifications();
  };

  return (
    <div className="dashboard-page">
      <section className="widget-grid">
        <div className="widget widget-blue">
          <h4>Total Items</h4>
          <p>{totalItems}</p>
        </div>
        <div className="widget widget-red">
          <h4>Lost Items</h4>
          <p>{dashboard.lostCount}</p>
        </div>
        <div className="widget widget-green">
          <h4>Found Items</h4>
          <p>{dashboard.foundCount}</p>
        </div>
        <div className="widget widget-amber">
          <h4>Resolved Items</h4>
          <p>{claimedCount}</p>
        </div>
        <div className="widget widget-navy">
          <h4>My Lost Reports</h4>
          <p>{myLostCount}</p>
        </div>
        <div className="widget widget-purple">
          <h4>Unread Alerts</h4>
          <p>{unreadCount}</p>
        </div>
      </section>

      <section className="panel">
        <div className="panel-title-row">
          <h3>Item Operations</h3>
          <div className="view-toggle">
            <button
              type="button"
              className={viewMode === "cards" ? "active" : ""}
              onClick={() => setViewMode("cards")}
            >
              Card View
            </button>
            <button
              type="button"
              className={viewMode === "table" ? "active" : ""}
              onClick={() => setViewMode("table")}
            >
              Table View
            </button>
          </div>
        </div>

        <form className="filter-row" onSubmit={handleSearch}>
          <input
            placeholder="Search by title"
            value={keyword}
            onChange={(e) => setKeyword(e.target.value)}
          />
          <input
            placeholder="Category"
            value={category}
            onChange={(e) => setCategory(e.target.value)}
          />
          <input
            placeholder="Location"
            value={location}
            onChange={(e) => setLocation(e.target.value)}
          />
          <select value={status} onChange={(e) => setStatus(e.target.value)}>
            <option value="">All Status</option>
            <option value="LOST">LOST</option>
            <option value="FOUND">FOUND</option>
            <option value="CLAIMED">CLAIMED</option>
            <option value="RETURNED">RETURNED</option>
            <option value="EXPIRED">EXPIRED</option>
          </select>
          <button type="submit">Search</button>
          <button type="button" onClick={handleFilter}>Apply Filter</button>
          <button type="button" className="ghost-btn" onClick={resetAll}>Reset</button>
        </form>

        {error ? <p className="error-text">{error}</p> : null}
        {loading ? <p className="helper-text">Loading records...</p> : null}
      </section>

      <section className="panel">
        <h3>Latest Items</h3>
        <div className="item-grid">
          {dashboard.latestItems && dashboard.latestItems.map((item) => (
            <ItemCard
              key={item.id}
              item={item}
              canManage={role === "ADMIN" || String(item.user?.id) === String(userId)}
              onEdit={handleEdit}
              onDelete={handleDelete}
              onReportFound={handleReportFound}
            />
          ))}
        </div>
      </section>

      <section className="dashboard-split">
        <div className="panel">
          <div className="panel-title-row">
            <h3>My Reports</h3>
            <button type="button" onClick={() => navigate("/add-item")}>Add New Report</button>
          </div>
          <div className="mini-list">
            {sortedMyItems.map((item) => (
              <div key={item.id} className="mini-list-item">
                <div>
                  <strong>{item.title}</strong>
                  <p>{item.status} at {item.location}</p>
                </div>
                <div className="inline-actions">
                  <button type="button" onClick={() => handleEdit(item)}>Edit</button>
                  <button type="button" className="ghost-btn" onClick={() => handleDelete(item.id)}>Delete</button>
                </div>
              </div>
            ))}
            {sortedMyItems.length === 0 ? <p className="helper-text">No personal reports yet.</p> : null}
          </div>
        </div>

        <div className="panel">
          <div className="panel-title-row">
            <h3>Notifications</h3>
            <span className="helper-text">{unreadCount} unread</span>
          </div>
          <div className="mini-list">
            {notifications.map((notification) => (
              <div key={notification.id} className={`mini-list-item ${notification.read ? "" : "unread-item"}`}>
                <div>
                  <strong>{notification.read ? "Read" : "New Alert"}</strong>
                  <p>{notification.message}</p>
                </div>
                {!notification.read ? (
                  <button type="button" className="ghost-btn" onClick={() => handleMarkRead(notification.id)}>
                    Mark Read
                  </button>
                ) : null}
              </div>
            ))}
            {notifications.length === 0 ? <p className="helper-text">No notifications yet.</p> : null}
          </div>
        </div>
      </section>

      <section className="panel">
        <h3>All Items</h3>
        {viewMode === "cards" ? (
          <div className="item-grid">
            {items.map((item) => (
              <ItemCard
                key={item.id}
                item={item}
                canManage={role === "ADMIN" || String(item.user?.id) === String(userId)}
                onEdit={handleEdit}
                onDelete={handleDelete}
                onReportFound={handleReportFound}
              />
            ))}
          </div>
        ) : (
          <div className="table-wrap">
            <table className="item-table">
              <thead>
                <tr>
                  <th>ID</th>
                  <th>Title</th>
                  <th>Category</th>
                  <th>Location</th>
                  <th>Status</th>
                  <th>Contact</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {items.map((item) => (
                  <tr key={item.id}>
                    <td>{item.id}</td>
                    <td>{item.title}</td>
                    <td>{item.category}</td>
                    <td>{item.location}</td>
                    <td>{item.status}</td>
                    <td>{item.contactInfo}</td>
                    <td className="inline-actions">
                      {(role === "ADMIN" || String(item.user?.id) === String(userId)) ? (
                        <>
                          <button type="button" onClick={() => handleEdit(item)}>Edit</button>
                          <button type="button" className="ghost-btn" onClick={() => handleDelete(item.id)}>Delete</button>
                        </>
                      ) : null}
                      {item.status === "LOST" ? (
                        <button type="button" className="ghost-btn" onClick={() => handleReportFound(item)}>
                          Report Found
                        </button>
                      ) : null}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </section>
    </div>
  );
}

export default Dashboard;
